mapper.update:
UPDATE forms
SET title = #{title}, description = #{description}, response_limit = #{responseLimit}
WHERE id = #{id}

mapper.select:
SELECT f.id AS id, f.slug AS slug, f.title AS title, f.status AS status, u.id AS owner_id, u.email AS owner_email, (SELECT COUNT(*) FROM responses r WHERE r.form_id = f.id) AS response_count, (SELECT COUNT(*) FROM form_reports fr WHERE fr.form_id = f.id AND fr.status = 'PENDING') AS pending_report_count, f.created_at AS created_at FROM forms f JOIN users u ON u.id = f.user_id WHERE f.deleted_at IS NULL
AND (f.slug LIKE CONCAT('%', #{keyword}, '%') OR f.title LIKE CONCAT('%', #{keyword}, '%') OR u.email LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY f.created_at DESC, f.id DESC LIMIT #{size} OFFSET #{offset}
